**Helper to convert (t, d) to world position**:
```js
function updateWorldPosition() {
  const clampedT = Math.max(0, Math.min(1, ball.t));
  const point = curve.getPointAt(clampedT);
  const tangent = curve.getTangentAt(clampedT).normalize();
  const up = new THREE.Vector3(0, 1, 0);
  const lateral = new THREE.Vector3().crossVectors(tangent, up).normalize();
  if (lateral.lengthSq() < 0.001) lateral.set(1, 0, 0);

  ball.worldX = point.x + lateral.x * ball.d;
  ball.worldY = point.y + trackConfig.trackHeight / 2 + trackConfig.ballRadius;
  ball.worldZ = point.z + lateral.z * ball.d;
}
```

Note: physics.js will need to import THREE for Vector3. Add `import * as THREE from 'three';` at the top.

**Rewrite `updateOnTrack(dt, tiltAngle, pitch)`**:
```js
function updateOnTrack(dt, tiltAngle, pitch) {
  // Slowdown timer
  if (slowdownActive) {
    slowdownTimer -= dt;
    if (slowdownTimer <= 0) {
      slowdownActive = false;
      slowdownTimer = 0;
    }
  }

  const effectiveForward = slowdownActive ? FORWARD_SPEED / 2 : FORWARD_SPEED;
  const effectiveMax = slowdownActive ? MAX_SPEED / 2 : MAX_SPEED;

  // Gravity slope boost from track tangent
  const clampedT = Math.max(0, Math.min(0.999, ball.t));
  const tangent = curve.getTangentAt(clampedT).normalize();
  const slopeBoost = -GRAVITY * tangent.y; // negative tangent.y = downhill = positive boost

  // Forward speed: base + pitch input + gravity slope
  const pitchVal = pitch || 0;
  ball.speed += slopeBoost * dt;
  const pitchModulated = effectiveForward * (1 + pitchVal * PITCH_SENSITIVITY);
  ball.speed = ball.speed * 0.95 + pitchModulated * 0.05; // blend gravity momentum with input
  ball.speed = Math.max(0, Math.min(effectiveMax, ball.speed));

  // Advance along curve
  ball.t += ball.speed * dt / curveLength;

  // Lateral movement from head tilt
  const targetVd = tiltAngle * DIRECT_SENSITIVITY;
  ball.vd += (targetVd - ball.vd) * RESPONSE_RATE * dt;
  ball.d += ball.vd * dt;

  // Edge check — fall off if lateral offset exceeds track width
  const halfWidth = trackConfig.trackWidth / 2;
  if (Math.abs(ball.d) > halfWidth) {
    ball.falling = true;
    ball.vy = 0;
    updateWorldPosition();
    return makeResult(false, false);
  }

  // Finish line check
  let finished = false;
  if (ball.t >= 1.0) {
    ball.t = 1.0;
    finished = true;
  }

  // Update world position from curve-local
  updateWorldPosition();

  // Obstacle collision — compare in curve-local space
  let obstacleHit = false;
  if (!ball.falling) {
    const br = trackConfig.ballRadius;
    const ballDist = ball.t * curveLength;
    for (const o of obstacles) {
      const oDist = o.t * curveLength;
      const dz = Math.abs(ballDist - oDist);
      const dx = Math.abs(ball.d - o.d);
      if (dz < (o.halfD + br) && dx < (o.halfW + br)) {
        ball.falling = true;
        ball.vy = 0;
        obstacleHit = true;
        break;
      }
    }
  }

  // Coin collection — curve-local distance
  const newlyCollected = [];
  const ballDist = ball.t * curveLength;
  for (let i = 0; i < coins.length; i++) {
    if (coinsCollected[i]) continue;
    const coinDist = coins[i].t * curveLength;
    const dz = ballDist - coinDist;
    const dx = ball.d - coins[i].d;
    const dist = Math.sqrt(dz * dz + dx * dx);
    if (dist < COIN_COLLECT_RADIUS) {
      coinsCollected[i] = true;
      newlyCollected.push(i);
    }
  }

  // Turtle collection — curve-local distance
  let turtleJustCollected = false;
  if (turtle && !turtleCollected) {
    const turtleDist = turtle.t * curveLength;
    const dz = ballDist - turtleDist;
    const dx = ball.d - turtle.d;
    const dist = Math.sqrt(dz * dz + dx * dx);
    if (dist < TURTLE_COLLECT_RADIUS) {
      turtleCollected = true;
      turtleJustCollected = true;
      slowdownActive = true;
      slowdownTimer = SLOWDOWN_DURATION;
    }
  }

  return {
    x: ball.worldX,
    y: ball.worldY,
    z: ball.worldZ,
    t: ball.t,
    vx: ball.vd,
    vz: ball.speed,
    falling: ball.falling,
    needsReset: false,
    obstacleHit,
    finished,
    coinsCollected: newlyCollected,
    turtleCollected: turtleJustCollected,
    slowdownActive,
  };
}
```

**Update `updateFalling(dt)`**: Use world coordinates for falling physics (gravity on Y, drift on XZ). Return `finished: false`.

```js
function updateFalling(dt) {
  ball.vy -= GRAVITY * dt;
  ball.worldY += ball.vy * dt;
  // Slight XZ drift
  ball.worldX += ball.vd * dt * 0.5;
  ball.worldZ += ball.speed * dt * 0.3;

  const needsReset = ball.worldY < -10;

  return {
    x: ball.worldX,
    y: ball.worldY,
    z: ball.worldZ,
    t: ball.t,
    vx: ball.vd,
    vz: ball.speed,
    falling: true,
    needsReset,
    obstacleHit: false,
    finished: false,
    coinsCollected: [],
    turtleCollected: false,
    slowdownActive,
  };
}
```

